<?php
require 'db_connection.php'; require_once 'helpers.php'; $conn=OpenCon(); $message='';
function randomPassword($length=10){ return substr(str_shuffle('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'),0,$length); }
if(isset($_POST['send'])){ $email=trim($_POST['email']); $stmt=$conn->prepare("SELECT id,email FROM users WHERE email=? LIMIT 1"); $stmt->bind_param("s",$email); $stmt->execute(); $user=$stmt->get_result()->fetch_assoc(); if(!$user){$message='Email not found.';} else { $newPass=randomPassword(); $hash=password_hash($newPass,PASSWORD_DEFAULT); $upd=$conn->prepare("UPDATE users SET password=?, attempts=0, blocked_until=0 WHERE id=?"); $upd->bind_param("si",$hash,$user['id']); $upd->execute(); $hist=$conn->prepare("INSERT INTO password_history (user_id,password) VALUES (?,?)"); $hist->bind_param("is",$user['id'],$hash); $hist->execute(); send_html_mail($email,'Temporary Password',"<h2>Password Reset</h2><p>Your temporary password is: <b>".e($newPass)."</b></p><p>Please login and change it from Account → Update Password.</p>"); $message='Temporary password sent to your email.'; }}
?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Forgot Password</title><link rel="stylesheet" href="css/style.css"></head><body><div class="form-box"><h2>Forgot Password</h2><?php if($message):?><p><?=e($message)?></p><?php endif;?><form method="post"><label>Email</label><input type="email" name="email" required><button name="send">Send</button></form><p><a href="login.php">Back to Login</a></p></div></body></html>
